import{_ as t,o as a,c as o,ae as i}from"./chunks/framework.BD9pLfSD.js";const p=JSON.parse('{"title":"MCP Integration: The Universal Interface","description":"","frontmatter":{},"headers":[],"relativePath":"docs/architecture/mcp-integration.md","filePath":"docs/architecture/mcp-integration.md"}'),r={name:"docs/architecture/mcp-integration.md"};function n(l,e,s,c,d,h){return a(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="mcp-integration-the-universal-interface" tabindex="-1">MCP Integration: The Universal Interface <a class="header-anchor" href="#mcp-integration-the-universal-interface" aria-label="Permalink to &quot;MCP Integration: The Universal Interface&quot;">​</a></h1><p>xB77 is built on the <strong>Model Context Protocol (MCP)</strong>, an open standard that enables AI models to interact with external tools and data sources seamlessly.</p><h2 id="why-mcp" tabindex="-1">Why MCP? <a class="header-anchor" href="#why-mcp" aria-label="Permalink to &quot;Why MCP?&quot;">​</a></h2><ul><li><strong>Model Agnostic:</strong> Whether you use Claude, GPT-4, or a local Llama model, the interface remains the same.</li><li><strong>Strict Security:</strong> Tools are explicitly defined. The LLM cannot execute arbitrary code; it can only request execution of validated financial tools.</li><li><strong>Context Awareness:</strong> The agent provides real-time state snapshots (balance, treasury efficiency, latest receipts) directly into the LLM&#39;s context window.</li></ul><h2 id="available-tools" tabindex="-1">Available Tools <a class="header-anchor" href="#available-tools" aria-label="Permalink to &quot;Available Tools&quot;">​</a></h2><p>The xB77 MCP Server exposes the following core capabilities:</p><ul><li><code>agent.pay</code>: Executes a payment with autonomous strategy selection.</li><li><code>agent.strategy.evaluate</code>: Pre-screens a transaction for risk and compliance.</li><li><code>agent.status</code>: Retrieves the current financial health of the agent.</li><li><code>agent.audit.report</code>: Generates a ZK-certified selective disclosure for a specific receipt.</li><li><code>cfo.treasury.rebalance</code>: Triggers autonomous liquidity management between rails.</li></ul>',7)])])}const m=t(r,[["render",n]]);export{p as __pageData,m as default};
